Script.Source:
                  import sailpoint.tools.Util;       
                  import sailpoint.object.Filter;
               
                  Filter activeFilter = Filter.eq("inactive", false);
                  String appValue = "";
                  if(null != form.getField("inputApplication") && Util.isNotNullOrEmpty( form.getField("inputApplication").getValue())){
                  	appValue = form.getField("inputApplication").getValue();
                  }
                 
                  Filter appFilter = Filter.eq("links.application.name", appValue);
                  Filter finalFilter = Filter.and(appFilter, activeFilter);
                 
                  field.setFilterString( finalFilter.getExpression() );

